import{_ as e,C as r,o as s,c as n,a2 as a,E as p}from"./chunks/framework.e-meDy3u.js";const g=JSON.parse('{"title":"附录：代理模式两手准备","description":"","frontmatter":{},"headers":[],"relativePath":"appendix/agent-modes.md","filePath":"appendix/agent-modes.md"}'),l={name:"appendix/agent-modes.md"};function u(i,t,h,d,q,_){const o=r("PushPull");return s(),n("div",null,[t[0]||(t[0]=a('<h1 id="附录-代理模式两手准备" tabindex="-1">附录：代理模式两手准备 <a class="header-anchor" href="#附录-代理模式两手准备" aria-label="Permalink to &quot;附录：代理模式两手准备&quot;">​</a></h1><p class="hqq-lede">方案中有一个关键假设尚待核实：代理是挂昊七七链接分销，还是各自开店自己卖。这个假设影响第三步怎么铺，但不影响地基和第一步。</p><h2 id="先把稳的东西钉住" tabindex="-1">先把稳的东西钉住 <a class="header-anchor" href="#先把稳的东西钉住" aria-label="Permalink to &quot;先把稳的东西钉住&quot;">​</a></h2><p>不管哪种代理模式，有一件事都对：<strong>已经赢过的爆款素材，得有个地方沉淀、打标签、排名，不能散在群聊和某几个人脑子里。</strong></p><p>爆款素材资产库这一层，两种情况都要建。分叉的不是库，是<strong>分发臂的姿态</strong>——是总部往下推（push），还是给代理一个自愿来取的货架（pull）。</p><hr><h2 id="分发臂-a-手-vs-b-手" tabindex="-1">分发臂：A 手 vs B 手 <a class="header-anchor" href="#分发臂-a-手-vs-b-手" aria-label="Permalink to &quot;分发臂：A 手 vs B 手&quot;">​</a></h2>',7)),p(o),t[1]||(t[1]=a('<hr><h2 id="两手都绕不开的三道坎" tabindex="-1">两手都绕不开的三道坎 <a class="header-anchor" href="#两手都绕不开的三道坎" aria-label="Permalink to &quot;两手都绕不开的三道坎&quot;">​</a></h2><p>不管 A 还是 B，只要提&quot;把已赢素材铺给代理&quot;，就会撞上这三件事：</p><p><strong>1. 抖音查重/搬运限流</strong></p><p>同一条视频原样搬到多个代理号发，平台会判重复内容限流；就算付费投，同素材多账号也是自己跟自己竞价内耗 + 素材疲劳。</p><p>解法：库分发给代理的是<strong>爆款配方</strong>（钩子结构、卖点话术、封面公式、脚本模板），要求代理各自重拍/改口播/换脸，不是原样成品。从源头绕开查重。</p><p><strong>2. 达人素材的授权/版权</strong></p><p>速食面抖音爆款很多是达人产出或出镜的。把达人素材沉进库再铺给代理，涉及版权、肖像权、分成——这是法务雷。</p><p>解法：库里的素材<strong>必带&quot;来源/授权状态&quot;字段</strong>（自有拍摄 / 达人授权可分发 / 仅限自营不可分发 / 需重新授权），分发臂对&quot;仅限自营&quot;的素材硬拦截，不许流到代理。</p><p><strong>3. 私店样板对代理的迁移性</strong></p><p>自营号和代理号在账号权重、粉丝画像、客群上都不同，自营跑赢的打法未必在代理号复现。</p><p>解法：话术上别把私店说成&quot;能直接复制到代理的样板&quot;，改成&quot;我先在私店跑通方法论和配方，迁移到代理时按各自实际再调参&quot;。样板证明的是方法论可行，不是素材放哪都赢。</p><hr><h2 id="我押哪一边" tabindex="-1">我押哪一边 <a class="header-anchor" href="#我押哪一边" aria-label="Permalink to &quot;我押哪一边&quot;">​</a></h2><p>给的线索是&quot;很多店铺都在做他们的代理&quot;——更像代理有自己的账号和内容，但巴不得总部给好弹药。纯 A 和纯 B 都是少数，真实生态大多是中间态。</p><p><strong>押注方向：按 B 手的&quot;货架&quot;姿态去搭，但保留 A 手的&quot;主动推&quot;能力。</strong> 库照建，分发默认做成&quot;自愿取用的货架 + 主动推荐给最配合的几个&quot;，数据回收默认走激励。对 A 不亏（愿意听的照样能被推），对 B 也成立（不听的当货架用）。一套东西，两边都不塌。</p><hr><h2 id="入职第一天的验证动作" tabindex="-1">入职第一天的验证动作 <a class="header-anchor" href="#入职第一天的验证动作" aria-label="Permalink to &quot;入职第一天的验证动作&quot;">​</a></h2><p>把&quot;待验证假设&quot;落成具体动作：</p><ol><li>第一天确认：代理是分销链接还是自开店，素材现在谁供，有没有总部统一发素材的先例。</li><li>找 1-2 个最配合的代理直接问：希望总部发成品素材，还是给参考模板自己改？愿不愿意回传数据？</li><li>拿这几个代理先跑样板，验证 push 还是 pull，再决定分发臂的实现。</li></ol>',20))])}const m=e(l,[["render",u]]);export{g as __pageData,m as default};
